/**
 * MedX split layout runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Resizable split panes for lot detail views.
 */
const SPLIT_TOKENS = Object.freeze({
  primary: { value: "layout-split-primary", scope: "layout" },
  secondary: { value: "layout-split-secondary", scope: "layout" },
  muted: { value: "layout-split-muted", scope: "layout" },
  accent: { value: "layout-split-accent", scope: "layout" },
  surface: { value: "layout-split-surface", scope: "layout" },
});

const SPLIT_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const SPLIT_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const splitRegistry = new Map();
const SPLIT_listeners = new Set();
let SPLIT_seq = 0;

function createSplitId(prefix = "medx-layout-split") {
  SPLIT_seq += 1;
  return `${prefix}-${SPLIT_seq}`;
}

function registerSplit(config = {}) {
  const entryId = config.id ?? createSplitId();
  const preset = SPLIT_PRESETS[config.preset ?? "default"] ?? SPLIT_PRESETS.default;
  const token = SPLIT_TOKENS[config.token ?? preset.token] ?? SPLIT_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: SPLIT_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  splitRegistry.set(entryId, entry);
  notifySplitListeners("register", entry);
  return entry;
}

function updateSplit(id, patch = {}) {
  const entry = splitRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifySplitListeners("update", entry);
  return entry;
}

function resolveSplit(id) {
  const entry = splitRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listSplitEntries(filter = {}) {
  let items = Array.from(splitRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onSplitEvent(listener) {
  SPLIT_listeners.add(listener);
  return () => SPLIT_listeners.delete(listener);
}

function notifySplitListeners(type, entry) {
  for (const listener of SPLIT_listeners) {
    try {
      listener({ type, entry, registrySize: splitRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:layout:split] listener error", err.message);
    }
  }
}

function getSplitMetrics() {
  const items = listSplitEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(SPLIT_TOKENS).length,
    presets: Object.keys(SPLIT_PRESETS).length,
  };
}

async function runMedxSplit() {
  console.log("[medx:ui:layout:split] runtime initialized");
  console.log(`[medx:ui:layout:split] tokens=${Object.keys(SPLIT_TOKENS).length} presets=${Object.keys(SPLIT_PRESETS).length}`);

  const events = [];
  onSplitEvent((e) => events.push(e.type));

  const domains = Object.keys(SPLIT_SUPPLY_CHAIN);
  const presets = Object.keys(SPLIT_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerSplit({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "layout/split" },
    });
  }

  const first = listSplitEntries()[0];
  if (first) updateSplit(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getSplitMetrics();
  const resolved = first ? resolveSplit(first.id) : null;

  console.log(`[medx:ui:layout:split] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:layout:split] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:layout:split] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:layout:split] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:layout:split] bootstrap complete");
}

module.exports = runMedxSplit;
